        e.preventDefault();
        if (passwords.new !== passwords.confirm) {
            alert('As palavras-passe n├úo coincidem.');
            return;
        }

        try {
            const { error } = await supabase.auth.updateUser({
                password: passwords.new
            });

            if (error) throw error;

            alert('Palavra-passe alterada com sucesso!');
            setPasswords({ new: '', confirm: '' });
        } catch (error) {
            console.error('Erro ao alterar palavra-passe:', error);
            alert('Erro ao alterar palavra-passe. Tente novamente.');
        }
    };

    const handleCancel = async (id: string) => {
        if (!confirm('Tem certeza que deseja cancelar este agendamento?')) return;
        try {
            const { error } = await supabase.from('Marcacoes').update({ status: 'cancelado' }).eq('id', id);
            if (error) throw error;
            setAppointments(prev => prev.map(apt => apt.id === id ? { ...apt, status: 'cancelado' } : apt));
        } catch (error) {
            console.error('Erro ao cancelar:', error);
            alert('Erro ao cancelar agendamento.');
        }
    };

    const handleReschedule = (apt: any) => {
        navigate('/agendar', {
            state: { 
                serviceName: apt.servicos.nome, 
                barberName: apt.barbeiros.nome, 
                editAppointmentId: apt.id,
                barberId: apt.barbeiros.id,
                serviceId: apt.servicos.id,
                serviceDuracao: apt.servicos.duracao,
                servicePreco: apt.servicos.preco
            }
        });
    };

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleDateString('pt-PT', { day: '2-digit', month: 'long', year: 'numeric' });
    };

    const formatTime = (dateString: string) => {
        return new Date(dateString).toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' });
    };

    const upcomingAppointments = appointments.filter(apt => apt.status === 'marcado' || apt.status === 'confirmado');
    const pastAppointments = appointments.filter(apt => apt.status === 'concluido' || apt.status === 'cancelado');

    const displayAppointments = activeTab === 'upcoming' ? upcomingAppointments : pastAppointments;

    return (
        <div className="min-h-screen bg-dark-bg text-gray-100">
            <PageHeader
                title={<>MEU <span className="text-primary">DASHBOARD</span></>}
                subtitle="Fa├ºa a gest├úo do seu perfil, agendamentos e encomendas."
                backgroundImage="https://images.unsplash.com/photo-1621605815971-fbc98d665033?q=80&w=2070&auto=format&fit=crop"
            />

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

                    {/* LEFT COLUMN: User Profile Card */}
                    <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="lg:col-span-1"
                    >
                        <div className="bg-dark/50 backdrop-blur-md border border-white/5 rounded-2xl p-6 sticky top-24 shadow-xl">
                            <div className="flex flex-col items-center text-center mb-6">
                                <div className="relative w-32 h-32 mb-4">
                                    <div className="absolute inset-0 bg-gradient-to-br from-primary to-yellow-600 rounded-full blur opacity-20"></div>
                                    <div className="relative w-full h-full bg-gray-800 rounded-full border-2 border-primary/50 flex items-center justify-center overflow-hidden">
                                        <User className="w-16 h-16 text-gray-400" />
                                    </div>
                                    <div className="absolute bottom-1 right-1 bg-dark border border-gray-700 rounded-full p-1.5" title="Seu Cargo">
                                        <Shield className="w-4 h-4 text-primary" />
                                    </div>
                                </div>

                                <h2 className="text-2xl font-heading font-bold text-white mb-1">{user?.user_metadata?.nome || 'Cliente'}</h2>
                                <p className="text-sm text-gray-400 mb-4">{role?.toUpperCase() || 'MEMBRO'}</p>

                                <button
                                    onClick={() => setActiveTab('settings')}
                                    className={clsx(
                                        "w-full flex items-center justify-center gap-2 py-2 text-sm rounded-lg transition-all",
                                        activeTab === 'settings'
                                            ? "bg-primary text-dark font-bold shadow-lg shadow-primary/20"
                                            : "btn-outline"
                                    )}
                                >
                                    <Edit2 className="w-4 h-4" /> Editar Perfil
                                </button>
                            </div>

                            <div className="space-y-4 border-t border-white/5 pt-6">
                                <div className="flex items-center gap-3 text-sm text-gray-300">
                                    <div className="w-8 h-8 rounded-lg bg-gray-800/50 flex items-center justify-center text-primary">
                                        <Mail className="w-4 h-4" />
                                    </div>
                                    <div className="flex-1 truncate">
                                        <p className="text-xs text-gray-500">Email</p>
                                        <p className="truncate" title={user?.email}>{user?.email}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3 text-sm text-gray-300">
                                    <div className="w-8 h-8 rounded-lg bg-gray-800/50 flex items-center justify-center text-primary">
                                        <Phone className="w-4 h-4" />
                                    </div>
                                    <div>
                                        <p className="text-xs text-gray-500">Telem├│vel</p>
                                        <p>{user?.user_metadata?.telemovel || 'N├úo definido'}</p>
                                    </div>
                                </div>
                            </div>

                            <button
                                onClick={signOut}
                                className="w-full mt-8 flex items-center justify-center gap-2 text-red-500 hover:text-red-400 hover:bg-red-500/10 py-3 rounded-lg transition-colors border border-transparent hover:border-red-500/20"
                            >
                                <LogOut className="w-4 h-4" /> Sair da Conta
                            </button>
                        </div>
                    </motion.div>

                    {/* RIGHT COLUMN: Appointments Dashboard */}
                    <div className="lg:col-span-2">
                        {/* Tabs */}
                        <div className="flex items-center gap-6 mb-8 border-b border-white/5 overflow-x-auto">
                            {[
                                { id: 'upcoming', label: 'Pr├│ximos' },
                                { id: 'history', label: 'Hist├│rico' },
                                { id: 'orders', label: 'Encomendas' },
                                { id: 'settings', label: 'Defini├º├Áes' }
                            ].map(tab => (
                                <button
                                    key={tab.id}
                                    onClick={() => setActiveTab(tab.id as any)}
                                    className={clsx(
                                        "pb-4 text-sm font-bold uppercase tracking-wider relative transition-colors whitespace-nowrap",
                                        activeTab === tab.id ? "text-primary" : "text-gray-500 hover:text-gray-300"
                                    )}
                                >
                                    {tab.label}
                                    {activeTab === tab.id && (
                                        <motion.div layoutId="activeTab" className="absolute bottom-0 left-0 w-full h-0.5 bg-primary" />
                                    )}
                                </button>
                            ))}
                        </div>

                        {loading ? (
                            <div className="flex justify-center py-20">
                                <Loader className="w-10 h-10 text-primary animate-spin" />
                            </div>
                        ) : activeTab === 'settings' ? (
                            // Settings Tab Content
                            <motion.div
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="space-y-6"
                            >
                                {/* Personal Details Card */}
                                <div className="bg-dark/40 border border-white/5 rounded-2xl p-6 sm:p-8">
                                    <h3 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
                                        <User className="w-5 h-5 text-primary" />
                                        Informa├º├Áes Pessoais
                                    </h3>

                                    <form onSubmit={handleProfileUpdate} className="space-y-6">
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                            <div className="space-y-2">
                                                <label className="text-sm text-gray-400">Nome Completo</label>
                                                <input
                                                    type="text"
                                                    value={profileData.nome}
                                                    onChange={(e) => setProfileData({ ...profileData, nome: e.target.value })}
                                                    className="w-full bg-black/40 border border-gray-700 rounded-lg px-4 py-3 text-white focus:border-primary focus:ring-1 focus:ring-primary focus:outline-none transition-all"
                                                />
                                            </div>
                                            <div className="space-y-2">
                                                <label className="text-sm text-gray-400">Telem├│vel</label>
                                                <input
                                                    type="tel"
                                                    value={profileData.telemovel}
                                                    onChange={(e) => setProfileData({ ...profileData, telemovel: e.target.value })}
                                                    className="w-full bg-black/40 border border-gray-700 rounded-lg px-4 py-3 text-white focus:border-primary focus:ring-1 focus:ring-primary focus:outline-none transition-all"
                                                />
                                            </div>
                                            <div className="space-y-2 md:col-span-2">
                                                <label className="text-sm text-gray-400">Email (N├úo edit├ível)</label>
                                                <div className="relative">
                                                    <input
                                                        type="email"
                                                        value={user?.email || ''}
                                                        disabled
                                                        className="w-full bg-black/20 border border-gray-800 rounded-lg px-4 py-3 text-gray-500 cursor-not-allowed pl-10"
                                                    />
                                                    <Lock className="w-4 h-4 text-gray-600 absolute left-3 top-3.5" />
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex justify-end pt-2">
                                            <button type="submit" className="btn-primary px-6 py-2.5 flex items-center gap-2">
                                                <Save className="w-4 h-4" />
                                                Guardar Informa├º├Áes
                                            </button>
                                        </div>
                                    </form>
                                </div>

                                {/* Security Card */}
                                <div className="bg-dark/40 border border-white/5 rounded-2xl p-6 sm:p-8">
                                    <h3 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
                                        <Shield className="w-5 h-5 text-primary" />
                                        Seguran├ºa da Conta
                                    </h3>

                                    <form onSubmit={handlePasswordUpdate} className="space-y-6">
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                            <div className="space-y-2">
                                                <label className="text-sm text-gray-400">Nova Palavra-passe</label>
                                                <input
                                                    type="password"
                                                    value={passwords.new}
                                                    onChange={(e) => setPasswords({ ...passwords, new: e.target.value })}
                                                    placeholder="M├¡nimo 6 caracteres"
                                                    className="w-full bg-black/40 border border-gray-700 rounded-lg px-4 py-3 text-white focus:border-primary focus:ring-1 focus:ring-primary focus:outline-none transition-all"
                                                />
                                            </div>
                                            <div className="space-y-2">
                                                <label className="text-sm text-gray-400">Confirmar Palavra-passe</label>
                                                <input
                                                    type="password"
                                                    value={passwords.confirm}
                                                    onChange={(e) => setPasswords({ ...passwords, confirm: e.target.value })}
                                                    placeholder="Repita a palavra-passe"
                                                    className="w-full bg-black/40 border border-gray-700 rounded-lg px-4 py-3 text-white focus:border-primary focus:ring-1 focus:ring-primary focus:outline-none transition-all"
                                                />
                                            </div>
                                        </div>
                                        <div className="flex justify-end pt-2">
                                            <button
                                                type="submit"
                                                className="bg-gray-800 hover:bg-gray-700 text-white font-medium px-6 py-2.5 rounded-lg flex items-center gap-2 transition-colors border border-gray-700"
                                                disabled={!passwords.new || !passwords.confirm}
                                            >
                                                <Lock className="w-4 h-4" />
                                                Atualizar Palavra-passe
                                            </button>
                                        </div>
                                    </form>
                                </div>
                            </motion.div>
                        ) : activeTab === 'orders' ? (
                            // ORDERS TAB Content
                            <div className="space-y-6">
                                {ordersLoading ? (
                                    <div className="text-center py-10"><Loader className="w-8 h-8 text-primary animate-spin mx-auto" /></div>
                                ) : orders.length > 0 ? (
                                    orders.map((order) => (
                                        <motion.div
                                            key={order.id}
                                            initial={{ opacity: 0, y: 20 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            className="bg-dark/40 border border-white/5 rounded-2xl overflow-hidden hover:border-primary/30 transition-all"
                                        >
                                            <div className="p-6">
                                                <div className="flex flex-wrap justify-between items-start gap-4 mb-4">
                                                    <div>
                                                        <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">Encomenda #{order.id.slice(0, 4)}</span>
                                                        <h4 className="text-lg font-bold text-white mt-1 flex items-center gap-2">
                                                            {new Date(order.created_at).toLocaleDateString('pt-PT')}
                                                            <span className={`text-xs px-2 py-0.5 rounded-full border ${order.status === 'entregue' ? 'bg-green-500/10 text-green-500 border-green-500/20' :
                                                                'bg-yellow-500/10 text-yellow-500 border-yellow-500/20'
                                                                }`}>
                                                                {order.status}
                                                            </span>
                                                        </h4>
                                                    </div>
                                                    <div className="text-right">
                                                        <span className="text-2xl font-bold text-primary">{order.total}Ôé¼</span>
                                                    </div>
                                                </div>

                                                <div className="bg-white/5 rounded-xl p-4 mb-4">
                                                    <ul className="space-y-2">
                                                        {order.itens?.map((item: any, i: number) => (
                                                            <li key={i} className="flex justify-between text-sm text-gray-300">
                                                                <span>{item.quantity}x {item.nome}</span>
                                                                <span className="font-bold">{item.preco}Ôé¼</span>
                                                            </li>
                                                        ))}
                                                    </ul>
                                                </div>

                                                {order.status !== 'entregue' && order.status !== 'cancelado' && (
                                                    <div className="flex items-center gap-4 bg-primary/10 p-3 rounded-xl border border-primary/20">
                                                        <div className="bg-white p-2 rounded-lg">
                                                            <QrCode className="w-6 h-6 text-black" />
                                                        </div>
                                                        <div>
                                                            <p className="text-xs text-primary font-bold uppercase tracking-wider">C├│digo de Levantamento</p>
                                                            <p className="text-xl font-mono font-bold text-white tracking-[0.2em]">{order.codigo}</p>
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                        </motion.div>
                                    ))
                                ) : (
                                    <div className="bg-dark/30 border border-white/5 rounded-2xl p-12 text-center flex flex-col items-center">
                                        <div className="w-16 h-16 bg-gray-800 rounded-full flex items-center justify-center mb-4">
                                            <ShoppingBag className="w-8 h-8 text-gray-500" />
                                        </div>
                                        <h3 className="text-xl font-bold text-white mb-2">Sem encomendas</h3>
                                        <p className="text-gray-400 mb-8 max-w-sm">Ainda n├úo realizou nenhuma compra na nossa loja.</p>
                                        <button onClick={() => navigate('/loja')} className="btn-primary px-8 py-3">
                                            Ir para a Loja
                                        </button>
                                    </div>
                                )}
                            </div>
                        ) : displayAppointments.length > 0 ? (
                            // Appointments List (Upcoming/History)
                            <div className="space-y-4">
                                <AnimatePresence mode="popLayout">
                                    {displayAppointments.map((apt) => (
                                        <motion.div
                                            key={apt.id}
                                            initial={{ opacity: 0, y: 20 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            exit={{ opacity: 0, scale: 0.95 }}
                                            className="bg-dark/40 border border-white/5 hover:border-primary/30 rounded-xl p-5 transition-all group"
                                        >
                                            <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
                                                <div className="flex items-start gap-4">
                                                    <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center text-primary mt-1">
                                                        <Scissors className="w-6 h-6" />
                                                    </div>
                                                    <div>
                                                        <h3 className="text-lg font-bold text-white group-hover:text-primary transition-colors">
                                                            {apt.servicos?.nome}
                                                        </h3>
                                                        <div className="flex items-center gap-4 text-sm text-gray-400 mt-1">
                                                            <div className="flex items-center gap-1">
                                                                <User className="w-3 h-3" />
                                                                {apt.barbeiros?.nome}
                                                            </div>
                                                            <div className="flex items-center gap-1">
                                                                <Clock className="w-3 h-3" />
                                                                {formatTime(apt.data_hora)}
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>

                                                <div className="flex flex-col items-end gap-2 pl-16 md:pl-0">
                                                    <div className="flex items-center gap-3">
                                                        <span className="text-white font-heading font-bold text-lg">
                                                            {formatDate(apt.data_hora)}
                                                        </span>
                                                        <span className={clsx(
                                                            "px-2.5 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wide border",
                                                            apt.status === 'confirmado' ? "bg-blue-500/10 text-blue-500 border-blue-500/20" :
                                                                apt.status === 'marcado' ? "bg-yellow-500/10 text-yellow-500 border-yellow-500/20" :
                                                                    apt.status === 'concluido' ? "bg-emerald-500/10 text-emerald-500 border-emerald-500/20" :
                                                                        "bg-red-500/10 text-red-500 border-red-500/20"
                                                        )}>
                                                            {apt.status}
                                                        </span>
                                                    </div>

                                                    {activeTab === 'upcoming' && (apt.status === 'marcado' || apt.status === 'confirmado') && (
                                                        <div className="flex items-center gap-2 mt-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                            <a
                                                                href={getGoogleCalendarUrl(
                                                                    `Corte - ${apt.servicos?.nome}`, 
                                                                    apt.data_hora, 
                                                                    apt.servicos?.duracao || 60
                                                                )}
                                                                target="_blank"
                                                                rel="noopener noreferrer"
                                                                className="p-2 hover:bg-blue-500/10 rounded-lg text-blue-500/70 hover:text-blue-500 transition-colors"
                                                                title="Adicionar ao Google Calendar"
                                                            >
                                                                <CalendarIcon className="w-4 h-4" />
                                                            </a>
                                                            <button
                                                                onClick={() => handleReschedule(apt)}
                                                                className="p-2 hover:bg-gray-700/50 rounded-lg text-gray-400 hover:text-white transition-colors"
                                                                title="Reagendar"
                                                            >
                                                                <Repeat className="w-4 h-4" />
                                                            </button>
                                                            <button
                                                                onClick={() => handleCancel(apt.id)}
                                                                className="p-2 hover:bg-red-500/10 rounded-lg text-red-500/70 hover:text-red-500 transition-colors"
                                                                title="Cancelar"
                                                            >
                                                                <X className="w-4 h-4" />
                                                            </button>
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        </motion.div>
                                    ))}
                                </AnimatePresence>
                            </div>
                        ) : (
                            // Empty State for Appointments
                            <div className="bg-dark/30 border border-white/5 rounded-2xl p-12 text-center flex flex-col items-center">
                                <div className="w-16 h-16 bg-gray-800 rounded-full flex items-center justify-center mb-4">
                                    <History className="w-8 h-8 text-gray-500" />
                                </div>
                                <h3 className="text-xl font-bold text-white mb-2">
                                    {activeTab === 'upcoming' ? "Sem agendamentos futuros" : "Sem hist├│rico recente"}
                                </h3>
                                <p className="text-gray-400 mb-8 max-w-sm">
                                    {activeTab === 'upcoming'
                                        ? "Voc├¬ n├úo tem nenhum corte agendado para os pr├│ximos dias."
                                        : "Voc├¬ ainda n├úo realizou agendamentos conosco."}
                                </p>
                                <button onClick={() => navigate('/agendar')} className="btn-primary px-8 py-3">
                                    Agendar Agora
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Profile;

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Star, User, MessageSquare, Send, Loader } from 'lucide-react';
import { supabase } from '../utils/supabase';
import { useAuth } from '../contexts/AuthContext';

interface Review {
    id: string;
    nota: number;
    comentario: string;
    created_at: string;
    perfis: {
        nome: string;
    };
}

import PageHeader from '../components/layout/PageHeader';

const Reviews: React.FC = () => {
    const { user } = useAuth();
    const [reviews, setReviews] = useState<Review[]>([]);
    const [loading, setLoading] = useState(true);
    const [rating, setRating] = useState(5);
    const [comment, setComment] = useState('');
    const [submitting, setSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    const fetchReviews = async () => {
        try {
            const { data, error } = await supabase
                .from('avaliacoes')
                .select(`
                    id,
                    nota,
                    comentario,
                    created_at,
                    perfis (nome)
                `)
                .order('created_at', { ascending: false });

            if (error) throw error;

            type ProfileData = { nome: string };

            interface ReviewData {
                id: string;
                nota: number;
                comentario: string;
                created_at: string;
                perfis: ProfileData | ProfileData[];
            }

            // Handle joined data structure
            const formattedReviews = (data as unknown as ReviewData[]).map(item => {
                const perfis = Array.isArray(item.perfis) ? item.perfis[0] : item.perfis;
                return {
                    ...item,
                    perfis: perfis ? { nome: perfis.nome } : { nome: 'Cliente' }
                };
            });

            setReviews(formattedReviews);
        } catch (err) {
            console.error('Erro ao buscar avalia├º├Áes:', err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReviews();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;

        setSubmitting(true);
        setError(null);
        setSuccess(false);

        try {
            const { error } = await supabase
                .from('avaliacoes')
                .insert([
                    {
                        cliente_id: user.id,
                        nota: rating,
                        comentario: comment,
                        barbeiro_id: null // General review for now
                    }
                ]);

            if (error) throw error;

            setSuccess(true);
            setComment('');
            setRating(5);
            fetchReviews(); // Refresh list
        } catch (err: any) {
            setError(err.message || 'Erro ao enviar avalia├º├úo');
        } finally {
            setSubmitting(false);
        }
    };

    return (
        <div className="min-h-screen bg-dark-bg">
            <PageHeader
                title={<>O QUE DIZEM <span className="text-primary">NOSSOS CLIENTES</span></>}
                subtitle="A satisfa├º├úo dos nossos clientes ├® a nossa maior recompensa."
                backgroundImage="https://images.unsplash.com/photo-1599351431202-1e0f0137899a?auto=format&fit=crop&q=80&w=1976"
            />

            <div className="max-w-4xl mx-auto px-4 py-16">
                {/* Submission Form */}
                {user ? (
                    <div className="bg-card-bg p-8 rounded-2xl border border-white/5 mb-16 shadow-xl relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-primary" />
                        <h3 className="text-2xl font-bold text-white mb-6 flex items-center">
                            <MessageSquare className="w-6 h-6 mr-3 text-primary" /> Deixe sua Avalia├º├úo
                        </h3>

                        {success && (
                            <div className="bg-green-500/10 border border-green-500/20 text-green-500 p-4 rounded-xl mb-6 flex items-center">
                                <Star className="w-5 h-5 mr-2 fill-current" />
                                Avalia├º├úo enviada com sucesso! Obrigado pelo feedback.
                            </div>
                        )}

                        {error && (
                            <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-4 rounded-xl mb-6">
                                {error}
                            </div>
                        )}

                        <form onSubmit={handleSubmit}>
                            <div className="mb-6">
                                <label className="block text-gray-400 mb-3 font-medium">Sua Nota</label>
                                <div className="flex space-x-2">
                                    {[1, 2, 3, 4, 5].map((star) => (
                                        <button
                                            key={star}
                                            type="button"
                                            onClick={() => setRating(star)}
                                            className={`focus:outline-none transition-transform hover:scale-110 ${star <= rating ? 'text-primary' : 'text-gray-700'}`}
                                        >
                                            <Star className="w-10 h-10 fill-current" />
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div className="mb-6">
                                <label className="block text-gray-400 mb-3 font-medium">Seu Coment├írio</label>
                                <textarea
                                    value={comment}
                                    onChange={(e) => setComment(e.target.value)}
                                    className="w-full bg-dark-bg border border-white/10 rounded-xl p-4 text-white focus:border-primary focus:outline-none h-32 transition-colors"
                                    placeholder="Conte-nos como foi sua experi├¬ncia..."
                                    required
                                />
                            </div>

                            <button
                                type="submit"
                                disabled={submitting}
                                className="btn-primary w-full flex justify-center items-center py-4 text-lg"
                            >
                                {submitting ? <Loader className="w-6 h-6 animate-spin mr-2" /> : <Send className="w-5 h-5 mr-2" />}
                                Enviar Avalia├º├úo
                            </button>
                        </form>
                    </div>
                ) : (
                    <div className="bg-card-bg p-10 rounded-2xl border border-white/5 mb-16 text-center shadow-xl">
                        <Star className="w-16 h-16 text-primary mx-auto mb-6 opacity-50" />
                        <h3 className="text-2xl font-bold text-white mb-4">Quer avaliar nossos servi├ºos?</h3>
                        <p className="text-gray-400 mb-8 max-w-md mx-auto">Fa├ºa login para compartilhar sua experi├¬ncia com a comunidade Barbearia Dourado.</p>
                        <a href="/login" className="btn-outline px-8 py-3">Entrar na Conta</a>
                    </div>
                )}

                {/* Reviews List */}
                {loading ? (
                    <div className="flex justify-center py-12">
                        <Loader className="w-10 h-10 text-primary animate-spin" />
                    </div>
                ) : reviews.length > 0 ? (
                    <div className="grid gap-6">
                        {reviews.map((review) => (
                            <motion.div
                                key={review.id}
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="bg-card-bg p-8 rounded-2xl border border-white/5 hover:border-primary/30 transition-all shadow-lg"
                            >
                                <div className="flex justify-between items-start mb-6">
                                    <div className="flex items-center">
                                        <div className="w-12 h-12 bg-dark-bg rounded-full flex items-center justify-center mr-4 border border-white/5 text-primary font-bold text-xl">
                                            {review.perfis?.nome ? review.perfis.nome.charAt(0).toUpperCase() : <User className="w-6 h-6" />}
                                        </div>
                                        <div>
                                            <h4 className="font-bold text-white text-lg">{review.perfis?.nome || 'Cliente'}</h4>
                                            <span className="text-sm text-gray-500">{new Date(review.created_at).toLocaleDateString('pt-PT')}</span>
                                        </div>
                                    </div>
                                    <div className="flex text-primary bg-primary/5 px-3 py-1 rounded-lg border border-primary/10">
                                        {[...Array(5)].map((_, i) => (
                                            <Star key={i} className={`w-4 h-4 ${i < review.nota ? 'fill-current' : 'text-gray-800'}`} />
                                        ))}
                                    </div>
                                </div>
                                <div className="relative">
                                    <span className="absolute -top-2 -left-2 text-6xl text-primary/10 font-serif">"</span>
                                    <p className="text-gray-300 italic text-lg leading-relaxed pl-6 relative z-10">{review.comentario}</p>
                                </div>
                            </motion.div>
                        ))}
                    </div>
                ) : (
                    <div className="text-center py-20">
                        <MessageSquare className="w-20 h-20 text-gray-800 mx-auto mb-6" />
                        <h3 className="text-2xl font-bold text-white mb-2">Nenhuma avalia├º├úo ainda</h3>
                        <p className="text-gray-500">Seja o primeiro a avaliar!</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Reviews;

import React, { useEffect, useState } from 'react';
import { format } from 'date-fns';
import { pt } from 'date-fns/locale';
import { Check, X, Search, Loader, Calendar as CalendarIcon, Clock, User, Scissors, List, Repeat } from 'lucide-react';
import { supabase } from '../../utils/supabase';
import { motion, AnimatePresence } from 'framer-motion';
import Calendar, { type CalendarEvent } from '../../components/Calendar';
import { getGoogleCalendarUrl } from '../../utils/calendar';

interface Appointment {
    id: string;
    data_hora: string;
    status: string;
    perfis: {
        nome: string;
        telemovel: string;
        email?: string;
    } | null;
    servicos: {
        nome: string;
        preco: number;
        duracao: number;
    } | null;
    barbeiros: {
        nome: string;
    } | null;
}

const AdminAppointments: React.FC = () => {
    const [appointments, setAppointments] = useState<Appointment[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [activeTab, setActiveTab] = useState('all');
    const [dateFilter, setDateFilter] = useState('');

    // Reschedule states
    const [reschedulingApt, setReschedulingApt] = useState<any>(null);
    const [newDate, setNewDate] = useState('');
    const [newTime, setNewTime] = useState('');

    // Calendar states
    const [viewMode, setViewMode] = useState<'list' | 'calendar'>('calendar');
    const [calendarView, setCalendarView] = useState<'month' | 'week' | 'day'>('week');
    const [currentDate, setCurrentDate] = useState(new Date());

    const fetchAppointments = async () => {
        setLoading(true);
        try {
            let query = supabase
                .from('Marcacoes')
                .select(`
                    id,
                    data_hora,
                    status,
                    perfis (nome, telemovel, email),
                    servicos (nome, preco, duracao),
                    barbeiros (nome)
                `)
                .order('data_hora', { ascending: true });

            // If a specific date is selected, filter by that day
            if (dateFilter) {
                const startDate = `${dateFilter}T00:00:00`;
                const endDate = `${dateFilter}T23:59:59`;
                query = query.gte('data_hora', startDate).lte('data_hora', endDate);
            } else {
                // If no date selected (Upcoming view), show from today onwards
                const today = new Date().toISOString().split('T')[0];
                const startDate = `${today}T00:00:00`;
                query = query.gte('data_hora', startDate);
            }

            const { data, error } = await query;

            if (error) throw error;

            type SectionData = { nome: string; telemovel?: string; email?: string; preco?: number; duracao?: number };

            interface AppointmentData {
                id: string;
                data_hora: string;
                status: string;
                perfis: SectionData | SectionData[];
                servicos: SectionData | SectionData[];
                barbeiros: SectionData | SectionData[];
            }
            const now = new Date();
            const formattedData = (data as unknown as AppointmentData[]).map(item => {
                const perfis = Array.isArray(item.perfis) ? item.perfis[0] : item.perfis;
                const servicos = Array.isArray(item.servicos) ? item.servicos[0] : item.servicos;
                const barbeiros = Array.isArray(item.barbeiros) ? item.barbeiros[0] : item.barbeiros;

                let currentStatus = item.status === 'pendente' ? 'marcado' : item.status;
                const aptDate = new Date(item.data_hora);
                const endDate = new Date(aptDate.getTime() + (servicos?.duracao || 30) * 60000);

                // Auto-conclude past appointments
                if ((currentStatus === 'marcado' || currentStatus === 'confirmado') && now > endDate) {
                    currentStatus = 'concluido';
                    supabase.from('Marcacoes').update({ status: 'concluido' }).eq('id', item.id).then();
                } else if (item.status === 'pendente') {
                    // Migrate legacy 'pendente' to 'marcado'
                    supabase.from('Marcacoes').update({ status: 'marcado' }).eq('id', item.id).then();
                }

                return {
                    ...item,
                    status: currentStatus,
                    perfis: perfis ? {
                        nome: perfis.nome,
                        telemovel: perfis.telemovel || '',
                        email: perfis.email
                    } : null,
                    servicos: servicos ? {
                        nome: servicos.nome,
                        preco: servicos.preco || 0,
                        duracao: servicos.duracao || 0
                    } : null,
                    barbeiros: barbeiros ? {
                        nome: barbeiros.nome
                    } : null
                };
            });

            setAppointments(formattedData);
        } catch (error) {
            console.error('Erro ao buscar agendamentos:', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchAppointments();
    }, [dateFilter]);

    const handleStatusUpdate = async (id: string, newStatus: string) => {
        try {
            const { error } = await supabase
                .from('Marcacoes')
                .update({ status: newStatus })
                .eq('id', id);

            if (error) throw error;

            setAppointments(prev => prev.map(apt =>
                apt.id === id ? { ...apt, status: newStatus } : apt
            ));
        } catch (error) {
            console.error('Erro ao atualizar status:', error);
        }
    };

    const handleRescheduleSubmit = async () => {
        if (!newDate || !newTime) return alert('Por favor, selecione a nova data e hora.');
        const novaDataHora = `${newDate}T${newTime}:00`;
        
        try {
            const { error } = await supabase
                .from('Marcacoes')
                .update({ data_hora: novaDataHora })
                .eq('id', reschedulingApt.id);

            if (error) throw error;
            
            fetchAppointments();
            setReschedulingApt(null);
            setNewDate('');
            setNewTime('');
            alert('Marca├º├úo reagendada com sucesso!');
        } catch (error) {
            console.error('Erro ao reagendar:', error);
            alert('Erro ao reagendar a marca├º├úo.');
        }
    };

    const filteredAppointments = appointments.filter(apt => {
        const matchesSearch = apt.perfis?.nome.toLowerCase().includes(searchTerm.toLowerCase());

        let matchesTab = true;
        if (activeTab === 'pending') matchesTab = apt.status === 'marcado' || apt.status === 'pendente';
        else if (activeTab === 'confirmed') matchesTab = apt.status === 'confirmado';
        else if (activeTab === 'history') matchesTab = apt.status === 'concluido' || apt.status === 'cancelado';

        return matchesSearch && matchesTab;
    });

    const getStatusStyle = (status: string) => {
        switch (status) {
            case 'confirmado': return 'bg-blue-500/15 text-blue-400 border-blue-500/30';
            case 'marcado': 
            case 'pendente': return 'bg-yellow-500/15 text-yellow-400 border-yellow-500/30';
            case 'cancelado': return 'bg-red-500/15 text-red-400 border-red-500/30';
            case 'concluido': return 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30';
            default: return 'bg-gray-500/10 text-gray-500 border-gray-500/20';
        }
    };

    const calendarEvents: CalendarEvent[] = filteredAppointments.map(apt => ({
        id: apt.id,
        title: apt.perfis?.nome || 'Cliente',
        subtitle: `${apt.servicos?.nome || 'V├írios'} ÔÇó ${apt.barbeiros?.nome || ''}`,
        start: new Date(apt.data_hora),
        end: new Date(new Date(apt.data_hora).getTime() + (apt.servicos?.duracao || 30) * 60000),
        status: apt.status,
        clientDetails: {
            name: apt.perfis?.nome || 'Cliente',
            phone: apt.perfis?.telemovel,
            email: apt.perfis?.email
        }
    }));

    return (
        <div className="space-y-6">
            <header className="flex flex-col md:flex-row justify-between items-end gap-4">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-white">Agendamentos</h1>
                    <p className="text-gray-400">Gerencie todas as marca├º├Áes da barbearia.</p>
                </div>

                <div className="flex bg-zinc-900 border border-white/10 rounded-xl p-1 items-center gap-2">
                    <div className="flex bg-black/40 rounded-lg p-0.5">
                        <button
                            onClick={() => setViewMode('list')}
                            className={`p-2 rounded-md transition-colors ${viewMode === 'list' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                            title="Ver em Lista"
                        >
                            <List className="w-5 h-5" />
                        </button>
                        <button
                            onClick={() => setViewMode('calendar')}
                            className={`p-2 rounded-md transition-colors ${viewMode === 'calendar' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                            title="Ver no Calend├írio"
                        >
                            <CalendarIcon className="w-5 h-5" />
                        </button>
                    </div>

                    {viewMode === 'list' && (
                        <>
                            <div className="w-px h-6 bg-white/10 mx-1"></div>
                            <input
                                type="date"
                                value={dateFilter}
                                onChange={(e) => setDateFilter(e.target.value)}
                                className="bg-transparent text-white px-2 py-1 outline-none cursor-pointer text-sm"
                            />
                            {dateFilter && (
                                <button
                                    onClick={() => setDateFilter('')}
                                    className="p-1 hover:bg-white/10 rounded-md text-gray-400 hover:text-white transition-colors mr-1"
                                    title="Ver Todos Futuros"
                                >
                                    <X className="w-4 h-4" />
                                </button>
                            )}
                        </>
                    )}
                </div>
            </header>

            {/* Filters (Only in List View) */}
            {viewMode === 'list' && (
                <div className="flex flex-col md:flex-row gap-4 items-center">
                <div className="relative flex-1 w-full">
                    <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-500 w-5 h-5" />
                    <input
                        type="text"
                        placeholder="Buscar por nome do cliente..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full bg-zinc-900/50 backdrop-blur-sm border border-white/10 rounded-xl py-3 pl-10 pr-4 text-white focus:border-primary/50 focus:ring-1 focus:ring-primary/50 outline-none transition-all"
                    />
                </div>

                <div className="flex p-1 bg-zinc-900/50 rounded-xl border border-white/10 overflow-x-auto max-w-full">
                    <button
                        onClick={() => setActiveTab('all')}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'all' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                    >
                        Todos
                    </button>
                    <button
                        onClick={() => setActiveTab('pending')}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'pending' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                    >
                        Marcados
                    </button>
                    <button
                        onClick={() => setActiveTab('confirmed')}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'confirmed' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                    >
                        Confirmados
                    </button>
                    <button
                        onClick={() => setActiveTab('history')}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'history' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                    >
                        Hist├│rico
                    </button>
                </div>
            </div>
            )}

            {/* Main Content Area */}
            {loading ? (
                <div className="flex justify-center py-20">
                    <Loader className="w-8 h-8 text-primary animate-spin" />
                </div>
            ) : viewMode === 'calendar' ? (
                <Calendar
                    events={calendarEvents}
                    view={calendarView}
                    onViewChange={setCalendarView}
                    currentDate={currentDate}
                    onDateChange={setCurrentDate}
                />
            ) : (
                <div className="space-y-4">
                    {filteredAppointments.length > 0 ? (
                    <AnimatePresence>
                        {filteredAppointments.map((apt) => (
                            <motion.div
                                layout
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.95 }}
                                key={apt.id}
                                className="bg-zinc-900/40 backdrop-blur-sm border border-white/5 rounded-2xl p-6 hover:border-primary/30 transition-all group"
                            >
                                <div className="flex flex-col lg:flex-row justify-between lg:items-center gap-6">

                                    {/* Time & Date */}
                                    <div className="flex items-center gap-4 min-w-[180px]">
                                        <div className="p-3 bg-white/5 rounded-xl text-primary group-hover:scale-110 transition-transform">
                                            <Clock className="w-6 h-6" />
                                        </div>
                                        <div>
                                            <p className="text-xl font-bold text-white">
                                                {format(new Date(apt.data_hora), "HH:mm")}
                                            </p>
                                            <p className="text-sm text-gray-500 capitalize">
                                                {format(new Date(apt.data_hora), "EEEE, d MMM", { locale: pt })}
                                            </p>
                                        </div>
                                    </div>

                                    {/* Client Info */}
                                    <div className="flex items-center gap-4 flex-1">
                                        <div className="hidden sm:flex w-10 h-10 rounded-full bg-zinc-800 items-center justify-center text-gray-400">
                                            <User className="w-5 h-5" />
                                        </div>
                                        <div>
                                            <p className="font-bold text-white">{apt.perfis?.nome || 'Cliente Desconhecido'}</p>
                                            <div className="flex items-center gap-3 text-sm text-gray-500">
                                                <span>{apt.perfis?.telemovel}</span>
                                                {apt.perfis?.email && (
                                                    <>
                                                        <span className="w-1 h-1 rounded-full bg-gray-700" />
                                                        <span>{apt.perfis.email}</span>
                                                    </>
                                                )}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Service Info */}
                                    <div className="flex items-center gap-4 flex-1">
                                        <div className="hidden sm:flex w-10 h-10 rounded-full bg-zinc-800 items-center justify-center text-gray-400">
                                            <Scissors className="w-5 h-5" />
                                        </div>
                                        <div>
                                            <p className="font-bold text-white">{apt.servicos?.nome || 'Servi├ºo Removido'}</p>
                                            <div className="flex items-center gap-3 text-sm text-gray-500">
                                                <span>{apt.servicos?.preco}Ôé¼</span>
                                                <span className="w-1 h-1 rounded-full bg-gray-700" />
                                                <span>{apt.servicos?.duracao} min</span>
                                                <span className="w-1 h-1 rounded-full bg-gray-700" />
                                                <span className="text-primary">{apt.barbeiros?.nome}</span>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Status & Actions */}
                                    <div className="flex items-center gap-4 justify-end">
                                        <div className={`px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-wider border ${getStatusStyle(apt.status)}`}>
                                            {apt.status}
                                        </div>

                                        <div className="flex gap-2">
                                            {(apt.status === 'marcado' || apt.status === 'confirmado' || apt.status === 'pendente') && (
                                                <>
                                                    <a
                                                        href={getGoogleCalendarUrl(
                                                            `Corte Cliente: ${apt.perfis?.nome}`,
                                                            apt.data_hora,
                                                            apt.servicos?.duracao || 60
                                                        )}
                                                        target="_blank"
                                                        rel="noopener noreferrer"
                                                        className="p-2 bg-blue-500/10 text-blue-500 rounded-lg hover:bg-blue-500/20 active:scale-95 transition-all"
                                                        title="Adicionar Lembrete Google"
                                                    >
                                                        <CalendarIcon className="w-5 h-5" />
                                                    </a>
                                                    <button
                                                        onClick={() => setReschedulingApt(apt)}
                                                        className="p-2 bg-zinc-700/50 text-gray-300 rounded-lg hover:bg-zinc-600 active:scale-95 transition-all"
                                                        title="Reagendar"
                                                    >
                                                        <Repeat className="w-5 h-5" />
                                                    </button>
                                                </>
                                            )}

                                            {(apt.status === 'marcado' || apt.status === 'pendente') && (
                                                <button
                                                    onClick={() => handleStatusUpdate(apt.id, 'confirmado')}
                                                    className="p-2 bg-green-500/10 text-green-500 rounded-lg hover:bg-green-500/20 active:scale-95 transition-all"
                                                    title="Confirmar"
                                                >
                                                    <Check className="w-5 h-5" />
                                                </button>
                                            )}
                                            
                                            {apt.status === 'confirmado' && (
                                                <button
                                                    onClick={() => handleStatusUpdate(apt.id, 'concluido')}
                                                    className="p-2 bg-emerald-500/10 text-emerald-500 rounded-lg hover:bg-emerald-500/20 active:scale-95 transition-all"
                                                    title="Concluir"
                                                >
                                                    <Check className="w-5 h-5" />
                                                </button>
                                            )}
                                            
                                            {(apt.status === 'marcado' || apt.status === 'pendente' || apt.status === 'confirmado') && (
                                                <button
                                                    onClick={() => handleStatusUpdate(apt.id, 'cancelado')}
                                                    className="p-2 bg-red-500/10 text-red-500 rounded-lg hover:bg-red-500/20 active:scale-95 transition-all"
                                                    title="Cancelar"
                                                >
                                                    <X className="w-5 h-5" />
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                ) : (
                    <div className="text-center py-20 bg-zinc-900/30 rounded-2xl border border-white/5 border-dashed">
                        <CalendarIcon className="w-16 h-16 mx-auto mb-4 text-gray-700" />
                        <h3 className="text-xl font-bold text-white mb-2">Sem agendamentos</h3>
                        <p className="text-gray-500">Nenhum agendamento encontrado para os filtros selecionados.</p>
                    </div>
                )}
                </div>
            )}

            {/* Reschedule Modal */}
            <AnimatePresence>
                {reschedulingApt && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.95 }}
                            className="bg-zinc-900 border border-white/10 rounded-2xl p-6 w-full max-w-sm shadow-2xl"
                        >
                            <h3 className="text-xl font-bold text-white mb-4">Reagendar Marca├º├úo</h3>
                            <p className="text-sm text-gray-400 mb-6">Selecione a nova data e hora para a marca├º├úo de <span className="text-white font-bold">{reschedulingApt.perfis?.nome || 'Cliente'}</span>.</p>
                            
                            <div className="space-y-4 mb-6">
                                <div>
                                    <label className="block text-sm text-gray-400 mb-1">Nova Data</label>
                                    <input 
                                        type="date"
                                        value={newDate}
                                        onChange={(e) => setNewDate(e.target.value)}
                                        className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-white outline-none focus:border-primary"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm text-gray-400 mb-1">Nova Hora</label>
                                    <input 
                                        type="time"
                                        value={newTime}
                                        onChange={(e) => setNewTime(e.target.value)}
                                        className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-white outline-none focus:border-primary"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-3">
                                <button onClick={() => setReschedulingApt(null)} className="flex-1 py-2 rounded-lg btn-outline">Cancelar</button>
                                <button onClick={handleRescheduleSubmit} className="flex-1 py-2 rounded-lg btn-primary">Confirmar</button>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default AdminAppointments;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { User, Mail, Lock, Check, ArrowLeft, Loader, Shield, Sparkles, Eye, EyeOff } from 'lucide-react';
import { supabase } from '../../utils/supabase';
import ImageUpload from '../../components/ui/ImageUpload';

const CreateBarber: React.FC = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [formData, setFormData] = useState({
        nome: '',
        bio: '',
        foto_url: '',
        email: '',
        password: '',
        confirmPassword: '',
        disponivel: true
    });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        if (!formData.password || formData.password.length < 6) {
            alert('A palavra-passe deve ter pelo menos 6 caracteres.');
            setLoading(false);
            return;
        }

        if (formData.password !== formData.confirmPassword) {
            alert('As palavras-passe n├úo coincidem.');
            setLoading(false);
            return;
        }

        try {
            const { error } = await supabase.rpc('admin_create_barber_v2', {
                p_email: formData.email,
                p_password: formData.password,
                p_nome: formData.nome,
                p_bio: formData.bio,
                p_foto_url: formData.foto_url,
                p_role: 'barbeiro' // Explicitly setting the role
            });

            if (error) throw error;

            // Success animation or redirect
            alert('Barbeiro criado com sucesso!');
            navigate('/admin/gerenciar');

        } catch (error: any) {
            console.error('Erro ao criar barbeiro:', error);

            // Handle specific error for duplicate email
            if (error.message?.includes('duplicate key') || error.message?.includes('users_email_partial_key')) {
                alert('Erro: Este endere├ºo de email j├í est├í registado. Por favor, utilize outro email.');
            } else {
                alert('Erro ao criar conta: ' + (error.message || 'Erro desconhecido'));
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-dark-bg text-white p-6 md:p-12 relative overflow-hidden">
