                        .select(`
                            id,
                            data_hora,
                            status,
                            perfis (nome, telemovel, email),
                            servicos (nome)
                        `)
                        .order('created_at', { ascending: false })
                        .limit(5)
                ]);

                // Calculate total revenue from the specific revenue query result
