import React, { useState, useEffect } from 'react';
import { supabase } from '../../utils/supabase';
import { Save, Loader, Edit, Trash, X, Search } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface UserProfile {
    id: string;
    nome: string;
    email: string;
    role: string;
    telemovel?: string;
}

const AdminManage: React.FC = () => {
    const [users, setUsers] = useState<UserProfile[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [activeTab, setActiveTab] = useState('all');
    const [editingId, setEditingId] = useState<string | null>(null);
    const [formData, setFormData] = useState<Partial<UserProfile>>({});
    const [currentUserId, setCurrentUserId] = useState<string | null>(null);

    useEffect(() => {
        fetchUsers();
        getCurrentUser();
    }, []);

    const getCurrentUser = async () => {
        const { data: { user } } = await supabase.auth.getUser();
        setCurrentUserId(user?.id || null);
    };

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('perfis')
                .select('*')
                .order('nome');

            if (error) throw error;
            setUsers(data || []);
        } catch (error) {
            console.error('Erro ao buscar utilizadores:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleEdit = (user: UserProfile) => {
        setEditingId(user.id);
        setFormData({
            nome: user.nome,
            email: user.email,
            role: user.role,
            telemovel: user.telemovel || ''
        });
    };

    const handleCancel = () => {
        setEditingId(null);
        setFormData({});
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('Tem certeza que deseja excluir este utilizador? Ao fazer isso, ele perder├í o acesso.')) return;

        try {
            // Note: Deleting from auth.users usually cascades to profiles, but we can't delete auth.users from client easily 
            // without a secure RPC function. However, assuming we just want to remove the profile or if there's a trigger...
            // Standard practice: Delete from profiles? Or better, just delete profile and let Supabase handle auth if configured.
            // CAUTION: Client-side delete of 'auth.users' is not possible.
            // We will delete the profile row.
            const { error } = await supabase.from('perfis').delete().eq('id', id);
            if (error) throw error;

            fetchUsers();
            alert('Utilizador removido com sucesso.');
        } catch (error: any) {
            console.error('Erro ao excluir:', error);
            alert('Erro ao excluir utilizador: ' + error.message);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            // Perform the update using the secure RPC function
            const { error } = await supabase.rpc('admin_update_user_v2', {
                p_user_id: editingId,
                p_nome: formData.nome,
                p_role: formData.role,
                p_telemovel: formData.telemovel
            });

            if (error) {
                console.error('RPC Error:', error);

                // Fallback or detailed error message
                if (error.message?.includes('function admin_update_user_v2') && error.message?.includes('does not exist')) {
                    alert(
                        'Erro: A fun├º├úo de atualiza├º├úo n├úo foi encontrada no banco de dados.\n\n' +
                        'Por favor, execute o script SQL "20251216_admin_update_user.sql" no Painel do Supabase para habilitar essa funcionalidade.'
                    );
                } else {
                    throw error;
                }
                return;
            }

            handleCancel();
            await fetchUsers();
            alert('Utilizador atualizado com sucesso!');
        } catch (error: any) {
            console.error('Erro ao salvar:', error);
            alert('Erro ao salvar utilizador: ' + error.message);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    const filteredUsers = users.filter(user => {
        const matchesSearch = user.nome?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            user.email?.toLowerCase().includes(searchTerm.toLowerCase());

        let matchesTab = true;
        if (activeTab === 'clients') matchesTab = user.role === 'client' || user.role === 'cliente'; // Handle both English/Portuguese just in case
        else if (activeTab === 'barbers') matchesTab = user.role === 'barbeiro' || user.role === 'barber';
        else if (activeTab === 'admins') matchesTab = user.role === 'admin';

        return matchesSearch && matchesTab;
    });

    return (
        <div className="space-y-6">
            <header className="flex flex-col md:flex-row justify-between items-center gap-4">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-white">Gest├úo de Utilizadores</h1>
                    <p className="text-gray-400">Gerencie permiss├Áes e dados dos utilizadores.</p>
                </div>

                <div className="flex gap-4 items-center">
                    <button
                        onClick={() => window.location.href = '/admin/criar-barbeiro'}
                        className="bg-primary text-black px-4 py-2 rounded-xl font-bold hover:bg-primary/90 transition-colors flex items-center gap-2"
                    >
                        + Novo Barbeiro
                    </button>
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-500 w-4 h-4" />
                        <input
                            type="text"
                            placeholder="Buscar utilizador..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="bg-zinc-900 border border-white/10 rounded-xl pl-10 pr-4 py-2 text-white focus:border-primary/50 outline-none w-64"
                        />
                    </div>
                </div>
            </header>

            {/* Tabs */}
            <div className="flex p-1 bg-zinc-900/50 rounded-xl border border-white/10 overflow-x-auto max-w-full w-fit mb-6">
                <button
                    onClick={() => setActiveTab('all')}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'all' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                >
                    Todos
                </button>
                <button
                    onClick={() => setActiveTab('clients')}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'clients' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                >
                    Clientes
                </button>
                <button
                    onClick={() => setActiveTab('barbers')}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'barbers' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                >
                    Barbeiros
                </button>
                <button
                    onClick={() => setActiveTab('admins')}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === 'admins' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                >
                    Administradores
                </button>
            </div>

            <AnimatePresence mode="wait">
                {editingId ? (
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -20 }}
                        className="bg-zinc-900/80 backdrop-blur-md p-8 rounded-2xl border border-primary/20 max-w-2xl mx-auto shadow-2xl relative overflow-hidden"
                    >
                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-primary to-transparent" />
                        <div className="flex justify-between items-center mb-8">
                            <h2 className="text-2xl font-bold text-white">Editar Utilizador</h2>
                            <button onClick={handleCancel} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-5 h-5 text-gray-400" /></button>
                        </div>

                        <form onSubmit={handleSave} className="space-y-6">
                            <div className="space-y-4">
                                <div>
                                    <label className="text-sm text-gray-400 font-medium ml-1 block mb-2">Email (Apenas leitura)</label>
                                    <input type="text" value={formData.email || ''} disabled
                                        className="w-full bg-black/40 border border-white/5 rounded-xl px-4 py-3 text-gray-500 cursor-not-allowed" />
                                </div>
                                <div>
                                    <label className="text-sm text-gray-400 font-medium ml-1 block mb-2">Nome</label>
                                    <input type="text" name="nome" value={formData.nome || ''} onChange={handleChange}
                                        className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-primary/50 focus:ring-1 focus:ring-primary/50 outline-none" required />
                                </div>
                                <div>
                                    <label className="text-sm text-gray-400 font-medium ml-1 block mb-2">Telem├│vel</label>
                                    <input type="text" name="telemovel" value={formData.telemovel || ''} onChange={handleChange}
                                        className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-primary/50 focus:ring-1 focus:ring-primary/50 outline-none" />
                                </div>
                                <div>
                                    <label className="text-sm text-gray-400 font-medium ml-1 block mb-2">Fun├º├úo (Role)</label>
                                    <select name="role" value={formData.role || 'client'} onChange={handleChange}
                                        className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-primary/50 focus:ring-1 focus:ring-primary/50 outline-none">
                                        <option value="client">Cliente</option>
                                        <option value="barbeiro">Barbeiro</option>
                                        <option value="admin">Administrador</option>
                                    </select>
                                    <p className="text-xs text-yellow-500/80 mt-2 ml-1">
                                        ÔÜá´©Å Aten├º├úo: "Barbeiro" d├í acesso ├á agenda e "Administrador" d├í acesso total ao sistema.
                                    </p>
                                </div>
                            </div>

                            <div className="flex justify-end gap-3 pt-6 border-t border-white/5">
                                <button type="button" onClick={handleCancel} className="px-6 py-2.5 rounded-xl text-gray-400 hover:text-white hover:bg-white/5 transition-colors font-medium">Cancelar</button>
                                <button type="submit" className="btn-primary px-8 py-2.5 font-bold rounded-xl shadow-lg shadow-primary/20 flex items-center">
                                    <Save className="w-4 h-4 mr-2" /> Salvar Altera├º├Áes
                                </button>
                            </div>
                        </form>
                    </motion.div>
                ) : (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
                    >
                        {loading ? (
                            <div className="col-span-full flex justify-center py-20">
                                <Loader className="w-8 h-8 text-primary animate-spin" />
                            </div>
                        ) : filteredUsers.length === 0 ? (
                            <div className="col-span-full text-center py-10 text-gray-500">Nenhum utilizador encontrado.</div>
                        ) : (
                            filteredUsers.map((user) => (
                                <motion.div layoutId={user.id} key={user.id} className="bg-zinc-900 border border-white/5 rounded-2xl p-5 flex items-center gap-4 hover:border-white/10 transition-colors group relative">
                                    <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
                                        {currentUserId !== user.id && (
                                            <>
                                                <button onClick={() => handleEdit(user)} className="p-2 bg-blue-500/10 text-blue-400 rounded-lg hover:bg-blue-500/20"><Edit className="w-4 h-4" /></button>
                                                <button onClick={() => handleDelete(user.id)} className="p-2 bg-red-500/10 text-red-400 rounded-lg hover:bg-red-500/20"><Trash className="w-4 h-4" /></button>
                                            </>
                                        )}
                                    </div>

                                    <div className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center text-gray-400 font-bold text-lg shrink-0">
                                        {user.nome ? user.nome.charAt(0).toUpperCase() : '?'}
                                    </div>
                                    <div className="overflow-hidden">
                                        <h3 className="font-bold text-white truncate">{user.nome || 'Sem Nome'}</h3>
                                        <p className="text-sm text-gray-500 truncate">{user.email}</p>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className={`text-xs px-2 py-0.5 rounded-full font-bold uppercase tracking-wider ${user.role === 'admin' ? 'bg-red-500/20 text-red-400' :
                                                user.role === 'barbeiro' || user.role === 'barber' ? 'bg-amber-500/20 text-amber-400' :
                                                    'bg-blue-500/20 text-blue-400'
                                                }`}>
                                                {user.role}
                                            </span>
                                            {user.telemovel && <span className="text-xs text-gray-600">{user.telemovel}</span>}
                                        </div>
                                    </div>
                                </motion.div>
                            ))
                        )}
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default AdminManage;

import React, { useState, useEffect } from 'react';
import { supabase } from '../../utils/supabase';
import { Save, Loader, Edit, Trash, X, Search, Plus, Scissors, Clock, DollarSign } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface Service {
    id: string;
    nome: string;
    preco: number;
    duracao: number;
}

const AdminServices: React.FC = () => {
    const [services, setServices] = useState<Service[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [isEditing, setIsEditing] = useState(false);
    const [currentService, setCurrentService] = useState<Partial<Service>>({});

    useEffect(() => {
        fetchServices();
    }, []);

    const fetchServices = async () => {
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('servicos')
                .select('*')
                .order('nome');

            if (error) throw error;
            setServices(data || []);
        } catch (error) {
            console.error('Erro ao buscar servi├ºos:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleEdit = (service: Service) => {
        setCurrentService(service);
        setIsEditing(true);
    };

    const handleNew = () => {
        setCurrentService({});
        setIsEditing(true);
    };

    const handleCancel = () => {
        setIsEditing(false);
        setCurrentService({});
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('Tem certeza que deseja excluir este servi├ºo?')) return;

        try {
            const { error } = await supabase.from('servicos').delete().eq('id', id);
            if (error) throw error;

            setServices(services.filter(s => s.id !== id));
            // alert('Servi├ºo removido com sucesso.');
        } catch (error: any) {
            console.error('Erro ao excluir:', error);
            alert('Erro ao excluir servi├ºo: ' + error.message);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            if (!currentService.nome || !currentService.preco || !currentService.duracao) {
                alert('Preencha todos os campos obrigat├│rios.');
                return;
            }

            const serviceData = {
                nome: currentService.nome,
                preco: parseFloat(currentService.preco.toString()),
                duracao: parseInt(currentService.duracao.toString())
            };

            if (currentService.id) {
                // Update
                const { error } = await supabase
                    .from('servicos')
                    .update(serviceData)
                    .eq('id', currentService.id);
                if (error) throw error;
            } else {
                // Create
                const { error } = await supabase
                    .from('servicos')
                    .insert([serviceData]);
                if (error) throw error;
            }

            handleCancel();
            fetchServices();
        } catch (error: any) {
            console.error('Erro ao salvar:', error);
            alert('Erro ao salvar servi├ºo: ' + error.message);
        }
    };

    const filteredServices = services.filter(service =>
        service.nome.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="space-y-6">
            <header className="flex flex-col md:flex-row justify-between items-center gap-4">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-white">Gest├úo de Servi├ºos</h1>
                    <p className="text-gray-400">Gerencie os servi├ºos oferecidos e seus pre├ºos.</p>
                </div>

                <div className="flex gap-4 items-center">
                    <button
                        onClick={handleNew}
                        className="bg-primary text-black px-4 py-2 rounded-xl font-bold hover:bg-primary/90 transition-colors flex items-center gap-2"
                    >
                        <Plus className="w-5 h-5" /> Novo Servi├ºo
                    </button>
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-500 w-4 h-4" />
                        <input
                            type="text"
                            placeholder="Buscar servi├ºo..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="bg-zinc-900 border border-white/10 rounded-xl pl-10 pr-4 py-2 text-white focus:border-primary/50 outline-none w-64"
                        />
                    </div>
                </div>
            </header>

            <AnimatePresence mode="wait">
                {isEditing ? (
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -20 }}
                        className="bg-zinc-900/80 backdrop-blur-md p-8 rounded-2xl border border-primary/20 max-w-2xl mx-auto shadow-2xl relative overflow-hidden"
                    >
                        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-primary to-transparent" />
                        <div className="flex justify-between items-center mb-8">
                            <h2 className="text-2xl font-bold text-white">
                                {currentService.id ? 'Editar Servi├ºo' : 'Novo Servi├ºo'}
                            </h2>
                            <button onClick={handleCancel} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X className="w-5 h-5 text-gray-400" /></button>
                        </div>

                        <form onSubmit={handleSave} className="space-y-6">
                            <div className="space-y-4">
                                <div>
                                    <label className="text-sm text-gray-400 font-medium ml-1 block mb-2">Nome do Servi├ºo</label>
                                    <div className="relative">
                                        <Scissors className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                                        <input
                                            type="text"
                                            value={currentService.nome || ''}
                                            onChange={e => setCurrentService({ ...currentService, nome: e.target.value })}
                                            className="w-full bg-black/40 border border-white/10 rounded-xl pl-12 pr-4 py-3 text-white focus:border-primary/50 focus:ring-1 focus:ring-primary/50 outline-none"
                                            placeholder="Ex: Corte Degrad├¬"
                                            required
                                        />
                                    </div>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="text-sm text-gray-400 font-medium ml-1 block mb-2">Pre├ºo (Ôé¼)</label>
                                        <div className="relative">
                                            <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                                            <input
                                                type="number"
                                                step="0.01"
                                                value={currentService.preco || ''}
                                                onChange={e => setCurrentService({ ...currentService, preco: parseFloat(e.target.value) })}
                                                className="w-full bg-black/40 border border-white/10 rounded-xl pl-12 pr-4 py-3 text-white focus:border-primary/50 focus:ring-1 focus:ring-primary/50 outline-none"
                                                placeholder="0.00"
                                                required
                                            />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="text-sm text-gray-400 font-medium ml-1 block mb-2">Dura├º├úo (min)</label>
                                        <div className="relative">
                                            <Clock className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                                            <input
                                                type="number"
                                                value={currentService.duracao || ''}
                                                onChange={e => setCurrentService({ ...currentService, duracao: parseInt(e.target.value) })}
                                                className="w-full bg-black/40 border border-white/10 rounded-xl pl-12 pr-4 py-3 text-white focus:border-primary/50 focus:ring-1 focus:ring-primary/50 outline-none"
                                                placeholder="30"
                                                required
                                            />
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="flex justify-end gap-3 pt-6 border-t border-white/5">
                                <button type="button" onClick={handleCancel} className="px-6 py-2.5 rounded-xl text-gray-400 hover:text-white hover:bg-white/5 transition-colors font-medium">Cancelar</button>
                                <button type="submit" className="btn-primary px-8 py-2.5 font-bold rounded-xl shadow-lg shadow-primary/20 flex items-center">
                                    <Save className="w-4 h-4 mr-2" /> Salvar Servi├ºo
                                </button>
                            </div>
                        </form>
                    </motion.div>
                ) : (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
                    >
                        {loading ? (
                            <div className="col-span-full flex justify-center py-20">
                                <Loader className="w-8 h-8 text-primary animate-spin" />
                            </div>
                        ) : filteredServices.length === 0 ? (
                            <div className="col-span-full text-center py-10 text-gray-500">Nenhum servi├ºo encontrado.</div>
                        ) : (
                            filteredServices.map((service) => (
                                <motion.div layoutId={service.id} key={service.id} className="bg-zinc-900 border border-white/5 rounded-2xl p-5 hover:border-white/10 transition-colors group relative">
                                    <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1">
                                        <button onClick={() => handleEdit(service)} className="p-2 bg-blue-500/10 text-blue-400 rounded-lg hover:bg-blue-500/20 transition-colors"><Edit className="w-4 h-4" /></button>
                                        <button onClick={() => handleDelete(service.id)} className="p-2 bg-red-500/10 text-red-400 rounded-lg hover:bg-red-500/20 transition-colors"><Trash className="w-4 h-4" /></button>
                                    </div>

                                    <div className="flex justify-between items-start mb-4">
                                        <div className="p-3 rounded-xl bg-primary/10 text-primary">
                                            <Scissors className="w-6 h-6" />
                                        </div>
                                        <span className="text-lg font-bold text-white">{service.preco}Ôé¼</span>
                                    </div>

                                    <h3 className="font-bold text-white text-lg mb-1">{service.nome}</h3>
                                    <div className="flex items-center text-sm text-gray-400">
                                        <Clock className="w-4 h-4 mr-1" />
                                        {service.duracao} minutos
                                    </div>
                                </motion.div>
                            ))
                        )}
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default AdminServices;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, Loader, Package, CheckCircle, AlertCircle, ShoppingBag, DollarSign, User, Phone, Mail } from 'lucide-react';
import { supabase } from '../../utils/supabase';
import { useAuth } from '../../contexts/AuthContext';
import PageHeader from '../../components/layout/PageHeader';

const VerifyOrder: React.FC = () => {
    const { } = useAuth(); // Only admin/barber can access
    const [code, setCode] = useState('');
    const [order, setOrder] = useState<any>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSearch = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setOrder(null);

        try {
            const { data, error } = await supabase
                .from('encomendas')
                .select(`
                    *,
                    cliente:perfis(nome, telemovel, email)
                `)
                .eq('codigo', code.toUpperCase())
                .single();

            if (error) throw error;
            if (!data) throw new Error('Encomenda n├úo encontrada.');

            setOrder(data);
        } catch (err: any) {
            console.error(err);
            setError('C├│digo inv├ílido ou encomenda n├úo encontrada.');
        } finally {
            setLoading(false);
        }
    };

    const handleDeliver = async () => {
        if (!order) return;
        if (!window.confirm('Confirmar entrega dos produtos?')) return;

        try {
            const { error } = await supabase
                .from('encomendas')
                .update({ status: 'entregue' })
                .eq('id', order.id);

            if (error) throw error;

            setOrder({ ...order, status: 'entregue' });
        } catch (err) {
            console.error(err);
            alert('Erro ao atualizar estado.');
        }
    };

    return (
        <div className="min-h-screen bg-dark-bg text-white pb-20">
            <PageHeader
                title="Validar Encomenda"
                subtitle="Valida├º├úo e entrega de pedidos"
                backgroundImage="https://images.unsplash.com/photo-1621609764095-6b2363a01048?auto=format&fit=crop&q=80"
            />

            <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 -mt-20 relative z-10">
                {/* Search Box */}
                <div className="bg-zinc-900/90 border border-white/10 rounded-3xl p-8 backdrop-blur-xl shadow-2xl mb-8">
                    <form onSubmit={handleSearch} className="flex flex-col md:flex-row gap-4">
                        <div className="relative flex-1 group">
                            <Search className="absolute left-5 top-1/2 transform -translate-y-1/2 text-gray-500 w-5 h-5 group-focus-within:text-primary transition-colors" />
                            <input
                                type="text"
                                value={code}
                                onChange={(e) => setCode(e.target.value)}
                                placeholder="Insira o c├│digo (ex: X7K9P2M8N1L5)"
                                className="w-full bg-black/40 border-2 border-transparent focus:border-primary/50 rounded-2xl py-4 pl-14 pr-4 text-white placeholder-gray-500 focus:outline-none focus:ring-4 focus:ring-primary/10 transition-all uppercase tracking-widest font-mono font-bold text-lg"
                            />
                        </div>
                        <button
                            type="submit"
                            disabled={loading || !code}
                            className="bg-primary hover:bg-primary/90 text-dark font-bold px-8 py-4 rounded-2xl transition-all hover:scale-105 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:scale-100 flex items-center justify-center gap-2 shadow-lg shadow-primary/20"
                        >
                            {loading ? <Loader className="w-5 h-5 animate-spin" /> : 'Verificar C├│digo'}
                        </button>
                    </form>

                    <AnimatePresence>
                        {error && (
                            <motion.div
                                initial={{ opacity: 0, height: 0 }}
                                animate={{ opacity: 1, height: 'auto' }}
                                exit={{ opacity: 0, height: 0 }}
                                className="mt-4 p-4 bg-red-500/10 border border-red-500/20 rounded-xl text-red-400 flex items-center gap-3"
                            >
                                <AlertCircle className="w-5 h-5 flex-shrink-0" />
                                <span className="font-medium">{error}</span>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>

                {/* Order Result */}
                <AnimatePresence mode='wait'>
                    {order && (
                        <motion.div
                            key={order.id}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.95 }}
                            transition={{ duration: 0.4 }}
                            className="bg-zinc-900 border border-white/10 rounded-3xl overflow-hidden shadow-2xl"
                        >
                            {/* Status Banner */}
                            <div className={`py-4 px-8 flex items-center justify-between font-bold uppercase tracking-widest text-sm
                                ${order.status === 'entregue'
                                    ? 'bg-emerald-500 text-emerald-950'
                                    : 'bg-amber-500 text-amber-950'}`}>
                                <span className="flex items-center gap-2">
                                    {order.status === 'entregue' ? <CheckCircle className="w-5 h-5" /> : <Package className="w-5 h-5" />}
                                    Estado: {order.status}
                                </span>
                                <span className="font-mono opacity-80">#{order.id.slice(0, 8)}</span>
                            </div>

                            <div className="p-8 grid md:grid-cols-2 gap-12">
                                {/* Left Column: Client & Totals */}
                                <div className="space-y-8">
                                    <div>
                                        <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-4">Cliente</h3>
                                        <div className="bg-white/5 rounded-2xl p-6 border border-white/5 space-y-4">
                                            <div className="flex items-center gap-4">
                                                <div className="w-12 h-12 bg-zinc-800 rounded-full flex items-center justify-center text-primary">
                                                    <User className="w-6 h-6" />
                                                </div>
                                                <div>
                                                    <p className="font-bold text-lg text-white">{order.cliente?.nome || 'Cliente'}</p>
                                                    <p className="text-gray-400 text-xs uppercase tracking-wide">Perfil de Cliente</p>
                                                </div>
                                            </div>
                                            <div className="border-t border-white/5 pt-4 space-y-3">
                                                <div className="flex items-center gap-3 text-gray-300">
                                                    <Mail className="w-4 h-4 text-gray-500" />
                                                    <span className="text-sm">{order.cliente?.email}</span>
                                                </div>
                                                <div className="flex items-center gap-3 text-gray-300">
                                                    <Phone className="w-4 h-4 text-gray-500" />
                                                    <span className="text-sm">{order.cliente?.telemovel || 'N/A'}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>

                                    <div>
                                        <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-4">Pagamento</h3>
                                        <div className="bg-gradient-to-br from-zinc-800 to-zinc-900 rounded-2xl p-6 border border-white/5 flex items-center justify-between">
                                            <div className="flex items-center gap-3 text-gray-400">
                                                <div className="p-2 bg-white/5 rounded-lg">
                                                    <DollarSign className="w-5 h-5" />
                                                </div>
                                                <span>Total do Pedido</span>
                                            </div>
                                            <span className="text-3xl font-bold text-primary">{order.total}Ôé¼</span>
                                        </div>
                                    </div>
                                </div>

                                {/* Right Column: Items & Actions */}
                                <div className="flex flex-col h-full">
                                    <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-4">Itens ({order.itens?.length || 0})</h3>
                                    <div className="bg-white/5 rounded-2xl border border-white/5 flex-1 max-h-[400px] overflow-y-auto custom-scrollbar">
                                        {order.itens?.map((item: any, i: number) => (
                                            <div key={i} className="flex items-center gap-4 p-4 border-b border-white/5 last:border-0 hover:bg-white/5 transition-colors">
                                                <div className="w-12 h-12 bg-black/40 rounded-lg flex items-center justify-center flex-shrink-0">
                                                    {item.imagem_url ? (
                                                        <img src={item.imagem_url} alt="" className="w-full h-full object-cover rounded-lg" />
                                                    ) : (
                                                        <ShoppingBag className="w-5 h-5 text-gray-600" />
                                                    )}
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <p className="font-bold text-white truncate">{item.nome}</p>
                                                    <p className="text-xs text-gray-500">{item.categoria}</p>
                                                </div>
                                                <div className="text-right">
                                                    <p className="font-mono text-primary font-bold">{(item.preco * item.quantity).toFixed(2)}Ôé¼</p>
                                                    <p className="text-xs text-gray-500">x{item.quantity}</p>
                                                </div>
                                            </div>
                                        ))}
                                    </div>

                                    {order.status !== 'entregue' ? (
                                        <motion.button
                                            whileHover={{ scale: 1.02 }}
                                            whileTap={{ scale: 0.98 }}
                                            onClick={handleDeliver}
                                            className="w-full mt-6 bg-emerald-500 hover:bg-emerald-400 text-emerald-950 font-bold py-4 rounded-2xl shadow-lg shadow-emerald-500/20 flex items-center justify-center gap-2 transition-all"
                                        >
                                            <CheckCircle className="w-5 h-5" />
                                            Confirmar Entrega
                                        </motion.button>
                                    ) : (
                                        <div className="mt-6 bg-white/5 border border-white/5 rounded-2xl p-4 text-center">
                                            <p className="text-emerald-400 font-bold flex items-center justify-center gap-2">
                                                <CheckCircle className="w-5 h-5" />
                                                Entregue com sucesso
                                            </p>
                                            <p className="text-xs text-gray-500 mt-1">Esta encomenda j├í foi processada.</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </div>
    );
};

export default VerifyOrder;

import React, { useEffect, useState } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { supabase } from '../../utils/supabase';
import { Calendar as CalendarIcon, Clock, User, Scissors, CheckCircle, AlertCircle, X, Repeat, Loader } from 'lucide-react';
import { getGoogleCalendarUrl } from '../../utils/calendar';
import Calendar, { type CalendarEvent } from '../../components/Calendar';
import { motion, AnimatePresence } from 'framer-motion';

const BarberDashboard: React.FC = () => {
    const { user } = useAuth();
    const [appointments, setAppointments] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({
        todayCount: 0,
        pendingCount: 0,
        completedCount: 0,
        totalRevenue: 0
    });
    const [activeTab, setActiveTab] = useState<'upcoming' | 'history' | 'cancelled' | 'calendar'>('calendar');

    // Calendar states
    const [calendarView, setCalendarView] = useState<'month' | 'week' | 'day'>('week');
    const [currentDate, setCurrentDate] = useState(new Date());

    // Reschedule State
    const [reschedulingApt, setReschedulingApt] = useState<any>(null);
    const [newDate, setNewDate] = useState('');
    const [newTime, setNewTime] = useState('');

    useEffect(() => {
        if (!user) return;
        fetchData();
    }, [user]);

    const fetchData = async () => {
        if (!user) return;
        try {
            // 1. Get Barber ID
            const { data: barberData, error: barberError } = await supabase
                .from('barbeiros')
                .select('id')
                .eq('id', user.id)
                .single();

            if (barberError || !barberData) {
                console.error("Barber not found linked to this user");
                setLoading(false);
                return;
            }

            // 2. Fetch Appointments
            const { data, error } = await supabase
                .from('Marcacoes')
                .select(`
                    *,
                    servico:servicos(nome, duracao, preco),
                    cliente:perfis(nome, telemovel, email)
                `)
                .eq('barbeiro_id', barberData.id)
                .order('data_hora', { ascending: true }); // Closest first

            if (error) throw error;
            const now = new Date();
            const apts = (data || []).map(item => {
                let currentStatus = item.status === 'pendente' ? 'marcado' : item.status;
                const aptDate = new Date(item.data_hora);
                const endDate = new Date(aptDate.getTime() + (item.servico?.duracao || 30) * 60000);

                if ((currentStatus === 'marcado' || currentStatus === 'confirmado') && now > endDate) {
                    currentStatus = 'concluido';
                    supabase.from('Marcacoes').update({ status: 'concluido' }).eq('id', item.id).then();
                } else if (item.status === 'pendente') {
                    // Migrate legacy 'pendente' to 'marcado'
                    supabase.from('Marcacoes').update({ status: 'marcado' }).eq('id', item.id).then();
                }
                
                return { ...item, status: currentStatus };
            });

            setAppointments(apts);

            // 3. Calculate Stats
            const today = new Date().toISOString().split('T')[0];
            const todayApts = apts.filter(a => a.data_hora.startsWith(today));
            const pending = apts.filter(a => a.status === 'marcado' || a.status === 'pendente');
            const completed = apts.filter(a => a.status === 'confirmado' || a.status === 'concluido'); // Assuming 'confirmado' roughly means confirmed/done contextually or user marks as done

            const revenue = completed.reduce((acc, curr) => {
                const price = curr.servico?.preco || 0;
                return acc + price;
            }, 0);

            setStats({
                todayCount: todayApts.length,
                pendingCount: pending.length,
                completedCount: completed.length,
                totalRevenue: revenue
            });

        } catch (error) {
            console.error('Error fetching data:', error);
        } finally {
            setLoading(false);
        }
    };



    if (loading) {
        return (
            <div className="min-h-screen bg-dark-bg text-white flex justify-center items-center">
                <Loader className="w-8 h-8 text-primary animate-spin" />
            </div>
        );
    }

    const container = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: { staggerChildren: 0.1 }
        }
    };

    const item = {
        hidden: { opacity: 0, y: 20 },
        show: { opacity: 1, y: 0 }
    };

    const statCards = [
        { title: 'Hoje', value: stats.todayCount, icon: CalendarIcon, color: 'text-blue-400', bg: 'from-blue-500/20 to-blue-600/5', border: 'border-blue-500/20' },
        { title: 'Marcados', value: stats.pendingCount, icon: AlertCircle, color: 'text-yellow-400', bg: 'from-yellow-500/20 to-yellow-600/5', border: 'border-yellow-500/20' },
        { title: 'Confirmados', value: stats.completedCount, icon: CheckCircle, color: 'text-emerald-400', bg: 'from-emerald-500/20 to-emerald-600/5', border: 'border-emerald-500/20' },
        { title: 'Receita Est.', value: `${stats.totalRevenue}Ôé¼`, icon: Scissors, color: 'text-purple-400', bg: 'from-purple-500/20 to-purple-600/5', border: 'border-purple-500/20' },
    ];

    const calendarEvents: CalendarEvent[] = appointments.map(apt => ({
        id: apt.id,
        title: apt.cliente?.nome || 'Cliente',
        subtitle: apt.servico?.nome || 'Servi├ºo',
        start: new Date(apt.data_hora),
        end: new Date(new Date(apt.data_hora).getTime() + (apt.servico?.duracao || 30) * 60000),
        status: apt.status,
        clientDetails: {
            name: apt.cliente?.nome || 'Cliente',
            phone: apt.cliente?.telemovel,
            email: apt.cliente?.email
        }
    }));

    const handleStatusUpdate = async (id: string, newStatus: string) => {
        if (!window.confirm(`Deseja alterar o status para "${newStatus}"?`)) return;

        try {
            const { error } = await supabase
                .from('Marcacoes')
                .update({ status: newStatus })
                .eq('id', id);

            if (error) throw error;
            fetchData(); // Refresh data
        } catch (error) {
            console.error('Error updating status:', error);
            alert('Erro ao atualizar status.');
        }
    };

    const handleRescheduleSubmit = async () => {
        if (!newDate || !newTime) return alert('Por favor, selecione a nova data e hora.');
        const novaDataHora = `${newDate}T${newTime}:00`;
        
        try {
            const { error } = await supabase
                .from('Marcacoes')
                .update({ data_hora: novaDataHora })
                .eq('id', reschedulingApt.id);

            if (error) throw error;
            
            fetchData();
            setReschedulingApt(null);
            setNewDate('');
            setNewTime('');
            alert('Marca├º├úo reagendada com sucesso!');
        } catch (error) {
            console.error('Erro ao reagendar:', error);
            alert('Erro ao reagendar a marca├º├úo.');
        }
    };

    return (
        <motion.div
            variants={container}
            initial="hidden"
            animate="show"
            className="min-h-screen bg-dark-bg text-white p-6 pt-24"
        >
            <header className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-white">Painel do Barbeiro</h1>
                    <p className="text-gray-400">Bem-vindo, {user?.user_metadata?.nome || 'Profissional'}</p>
                </div>
                <div className="flex gap-4">

                </div>
            </header>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                {statCards.map((stat, index) => (
                    <motion.div
                        key={index}
                        variants={item}
                        whileHover={{ y: -5 }}
                        className={`p-4 rounded-xl border ${stat.border} bg-gradient-to-br ${stat.bg} backdrop-blur-sm relative overflow-hidden group`}
                    >
                        <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                            <stat.icon className="w-16 h-16" />
                        </div>
                        <div className="relative z-10">
                            <div className={`p-3 rounded-lg w-fit mb-4 bg-black/20 ${stat.color}`}>
                                <stat.icon className="w-6 h-6" />
                            </div>
                            <h3 className="text-3xl font-bold text-white mb-1">{stat.value}</h3>
                            <p className="text-gray-400 text-sm font-medium uppercase tracking-wide">{stat.title}</p>
                        </div>
                    </motion.div>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Main Action Area: Appointments List */}
                <motion.div variants={item} className="lg:col-span-2 space-y-8">
                    <div className="bg-zinc-900/50 border border-white/5 rounded-2xl p-6 backdrop-blur-sm">
                        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
                            <h2 className="text-xl font-bold text-white">Seus Agendamentos</h2>

                            <div className="flex p-1 bg-black/40 rounded-lg border border-white/5">
                                <button
                                    onClick={() => setActiveTab('calendar')}
                                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'calendar' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                                >
                                    Calend├írio
                                </button>
                                <button
                                    onClick={() => setActiveTab('upcoming')}
                                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'upcoming' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                                >
                                    Pr├│ximos
                                </button>
                                <button
                                    onClick={() => setActiveTab('history')}
                                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'history' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                                >
                                    Hist├│rico
                                </button>
                                <button
                                    onClick={() => setActiveTab('cancelled')}
                                    className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'cancelled' ? 'bg-zinc-800 text-white shadow-sm' : 'text-gray-400 hover:text-white'}`}
                                >
                                    Cancelados
                                </button>
                            </div>
                        </div>

                        {activeTab === 'calendar' ? (
                            <Calendar
                                events={calendarEvents}
                                view={calendarView}
                                onViewChange={setCalendarView}
                                currentDate={currentDate}
                                onDateChange={setCurrentDate}
                            />
                        ) : appointments.filter(apt => {
                            if (activeTab === 'upcoming') return apt.status === 'marcado' || apt.status === 'pendente' || apt.status === 'confirmado';
                            if (activeTab === 'history') return apt.status === 'concluido';
                            if (activeTab === 'cancelled') return apt.status === 'cancelado';
                            return true;
                        }).length > 0 ? (
                            <div className="space-y-3">
                                {appointments
                                    .filter(apt => {
                                        if (activeTab === 'upcoming') return apt.status === 'marcado' || apt.status === 'pendente' || apt.status === 'confirmado';
                                        if (activeTab === 'history') return apt.status === 'concluido';
                                        if (activeTab === 'cancelled') return apt.status === 'cancelado';
                                        return true;
                                    })
                                    .map((apt) => (
                                        <div key={apt.id} className="flex flex-col md:flex-row items-start md:items-center justify-between p-4 rounded-xl bg-white/5 hover:bg-white/10 transition-colors border border-white/5 group gap-4">
                                            <div className="flex items-center gap-4">
                                                <div className="w-12 h-12 rounded-full bg-zinc-800 flex items-center justify-center text-gray-400 group-hover:text-primary transition-colors shrink-0">
                                                    <User className="w-6 h-6" />
                                                </div>
                                                <div>
                                                    <p className="font-bold text-white text-lg">
                                                        {apt.cliente?.nome || 'Cliente Desconhecido'}
                                                    </p>
                                                    
                                                    <div className="flex flex-col gap-1 mt-1">
                                                        <div className="flex items-center gap-2 text-sm text-gray-400">
                                                            <div className="flex items-center gap-1">
                                                                <span className="text-gray-300">{apt.cliente?.telemovel}</span>
                                                            </div>
                                                            {apt.cliente?.email && (
                                                                <>
                                                                    <span className="w-1 h-1 rounded-full bg-gray-600"></span>
                                                                    <span className="text-gray-300">{apt.cliente.email}</span>
                                                                </>
                                                            )}
                                                        </div>
                                                        <div className="flex items-center gap-2 text-sm text-gray-400">
                                                            <Scissors className="w-3 h-3" />
                                                            {apt.servico?.nome}
                                                            <span className="text-primary font-bold">({apt.servico?.preco}Ôé¼)</span>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>

                                            <div className="flex flex-row md:flex-col items-center md:items-end gap-3 md:gap-1 w-full md:w-auto justify-between md:justify-end pl-16 md:pl-0">
                                                <div className="flex items-center gap-2 text-gray-300">
                                                    <Clock className="w-4 h-4 text-primary" />
                                                    <span className="font-medium">
                                                        {new Date(apt.data_hora).toLocaleDateString('pt-PT', { day: '2-digit', month: '2-digit' })}
                                                        <span className="mx-1">ÔÇó</span>
                                                        {new Date(apt.data_hora).toLocaleTimeString('pt-PT', { hour: '2-digit', minute: '2-digit' })}
                                                    </span>
                                                </div>

                                                <div className="flex items-center gap-2 mt-2">
                                                    <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase tracking-wider
                                                    ${apt.status === 'confirmado' ? 'bg-blue-500/20 text-blue-400' :
                                                            (apt.status === 'marcado' || apt.status === 'pendente') ? 'bg-yellow-500/20 text-yellow-400' :
                                                                apt.status === 'concluido' ? 'bg-emerald-500/20 text-emerald-400' : 'bg-red-500/20 text-red-400'
                                                        }`}>
                                                        {apt.status === 'pendente' ? 'marcado' : apt.status}
                                                    </span>
                                                </div>

                                                {/* Action Buttons */}
                                                {(apt.status === 'marcado' || apt.status === 'confirmado') && (
                                                    <div className="flex flex-col items-end gap-2 shrink-0">
                                                        <div className="flex items-center gap-1 bg-black/40 p-1 rounded-lg border border-white/5 opacity-0 group-hover:opacity-100 transition-opacity">
                                                            <a
                                                                href={getGoogleCalendarUrl(
                                                                    `Corte Cliente: ${apt.cliente?.nome}`,
                                                                    apt.data_hora,
                                                                    apt.servico?.duracao || 60
                                                                )}
                                                                target="_blank"
                                                                rel="noopener noreferrer"
                                                                className="p-1 hover:bg-blue-500/20 rounded text-blue-400 transition-colors"
                                                                title="Criar Lembrete Google"
                                                            >
                                                                <CalendarIcon className="w-5 h-5" />
                                                            </a>
                                                            <button
                                                                onClick={() => setReschedulingApt(apt)}
                                                                className="p-1 hover:bg-gray-700/50 rounded text-gray-400 hover:text-white transition-colors"
                                                                title="Reagendar"
                                                            >
                                                                <Repeat className="w-5 h-5" />
                                                            </button>
                                                            <button
                                                                onClick={() => handleStatusUpdate(apt.id, 'confirmado')}
                                                                className="p-1 hover:bg-emerald-500/20 rounded text-emerald-500 transition-colors"
                                                                title="Confirmar Presen├ºa"
                                                            >
                                                                <CheckCircle className="w-5 h-5" />
                                                            </button>
                                                            <button
                                                                onClick={() => handleStatusUpdate(apt.id, 'cancelado')}
                                                                className="p-1 hover:bg-red-500/20 rounded text-red-500 transition-colors"
                                                                title="Cancelar"
                                                            >
                                                                <X className="w-5 h-5" />
                                                            </button>
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    ))}
                            </div>
                        ) : (
                            <div className="text-center py-16 text-gray-500">
                                <CalendarIcon className="w-16 h-16 mx-auto mb-4 opacity-20" />
                                <p className="text-lg">Sem agendamentos encontrados.</p>
                            </div>
                        )}
                    </div>
                </motion.div>

                {/* Quick Actions Sidebar */}
                <motion.div variants={item} className="space-y-6">
                    <div className="bg-zinc-900/50 border border-white/5 rounded-2xl p-6 backdrop-blur-sm">
                        <h2 className="text-xl font-bold text-white mb-6">Informa├º├Áes</h2>
                        <div className="space-y-4">
                            <div className="p-4 rounded-xl bg-white/5 border border-white/5">
                                <h3 className="font-bold text-white mb-1">Dica do Dia</h3>
                                <p className="text-sm text-gray-400">Mantenha sua disponibilidade atualizada para evitar conflitos.</p>
                            </div>

                            <div className="p-4 rounded-xl bg-primary/10 border border-primary/20">
                                <h3 className="font-bold text-primary mb-1">Suporte</h3>
                                <p className="text-sm text-gray-400">Precisa de ajuda com o sistema? Contate o administrador.</p>
                            </div>
                        </div>
                    </div>
                </motion.div>
            </div>

            {/* Reschedule Modal */}
            <AnimatePresence>
                {reschedulingApt && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
                        <motion.div
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.95 }}
                            className="bg-zinc-900 border border-white/10 rounded-2xl p-6 w-full max-w-sm shadow-2xl"
                        >
                            <h3 className="text-xl font-bold text-white mb-4">Reagendar Marca├º├úo</h3>
                            <p className="text-sm text-gray-400 mb-6">Selecione a nova data e hora para a marca├º├úo de <span className="text-white font-bold">{reschedulingApt.cliente?.nome || 'Cliente'}</span>.</p>
                            
                            <div className="space-y-4 mb-6">
                                <div>
                                    <label className="block text-sm text-gray-400 mb-1">Nova Data</label>
                                    <input 
                                        type="date"
                                        value={newDate}
                                        onChange={(e) => setNewDate(e.target.value)}
                                        className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-white outline-none focus:border-primary"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm text-gray-400 mb-1">Nova Hora</label>
                                    <input 
                                        type="time"
                                        value={newTime}
                                        onChange={(e) => setNewTime(e.target.value)}
                                        className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-white outline-none focus:border-primary"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-3">
                                <button onClick={() => setReschedulingApt(null)} className="flex-1 py-2 rounded-lg btn-outline">Cancelar</button>
                                <button onClick={handleRescheduleSubmit} className="flex-1 py-2 rounded-lg btn-primary">Confirmar</button>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </motion.div>
    );
};

export default BarberDashboard;

import { supabase } from './supabase';
import { addMinutes, format, isBefore, isAfter, set } from 'date-fns';

export interface TimeSlot {
    time: string;
    available: boolean;
    barberId?: string; // If 'any' was selected, this suggests a barber who is free
}

const OPENING_HOUR = 9;
const CLOSING_HOUR = 19;
const SLOT_INTERVAL = 30; // minutes

export const getRealAvailableSlots = async (
    dateStr: string,
    serviceDuration: number,
    barberId: string | 'any',
    excludeAppointmentId?: string
): Promise<TimeSlot[]> => {
    // 1. Fetch necessary data
    // If specific barber, fetch only their appointments.
    // If 'any', fetch ALL appointments for that date.

    // Parse date range for the query (Start of day to End of day)
    const startOfDay = `${dateStr}T00:00:00`;
    const endOfDay = `${dateStr}T23:59:59`;

    let query = supabase
        .from('Marcacoes')
        .select(`
            id,
            data_hora,
            barbeiro_id,
            servicos (duracao)
        `)
        .gte('data_hora', startOfDay)
        .lte('data_hora', endOfDay)
        .neq('status', 'cancelado'); // Ignore cancelled

    if (barberId !== 'any') {
        query = query.eq('barbeiro_id', barberId);
    }
    
    if (excludeAppointmentId) {
        query = query.neq('id', excludeAppointmentId);
    }

    const { data: appointments, error } = await query;
    if (error) {
        console.error('Error fetching appointments:', error);
        return [];
    }

    // If 'any', we also need the list of all active barbers to check them one by one
    let allBarbers: string[] = [];
    if (barberId === 'any') {
        const { data: barbers } = await supabase
            .from('barbeiros')
            .select('id')
            .eq('disponivel', true);
        allBarbers = barbers?.map(b => b.id) || [];
    } else {
        allBarbers = [barberId];
    }

    // 2. Generate all potential slots
    const slots: TimeSlot[] = [];
    let currentTime = set(new Date(dateStr), { hours: OPENING_HOUR, minutes: 0, seconds: 0 });
    const closeTime = set(new Date(dateStr), { hours: CLOSING_HOUR, minutes: 0, seconds: 0 });

    // Helper to check overlap
    const isBarberBusy = (bId: string, slotStart: Date, slotEnd: Date) => {
        return appointments?.some(apt => {
            if (apt.barbeiro_id !== bId) return false;

            // Calculate apt start and end
            const aptStart = new Date(apt.data_hora);
            // Default to 30 min if service duration missing (shouldn't happen)
            const serviceData = Array.isArray(apt.servicos) ? apt.servicos[0] : apt.servicos;
            const duration = (serviceData as any)?.duracao || 30;
            const aptEnd = addMinutes(aptStart, duration);

            // Check overlap: (StartA < EndB) and (EndA > StartB)
            return isBefore(slotStart, aptEnd) && isAfter(slotEnd, aptStart);
        });
    };

    while (isBefore(currentTime, closeTime)) {
        const timeLabel = format(currentTime, 'HH:mm');
        const slotEnd = addMinutes(currentTime, serviceDuration);

        // Check if slot exceeds closing time
        if (isAfter(slotEnd, closeTime)) {
            // Skip if service duration pushes past closing
            currentTime = addMinutes(currentTime, SLOT_INTERVAL);
            continue;
        }

        const now = new Date();
        let isAvailable = false;
        let candidateBarber: string | undefined = undefined;

        if (isBefore(currentTime, now)) {
            isAvailable = false; // Cannot book in the past
        } else {
            // Check availability logic
            // We look for ONE barber who is free for the entire duration [currentTime, slotEnd]
            for (const bId of allBarbers) {
                if (!isBarberBusy(bId, currentTime, slotEnd)) {
                    isAvailable = true;
                    candidateBarber = bId;
                    break; // Found one, that's enough to show the slot as available
                }
            }
        }

        slots.push({
            time: timeLabel,
            available: isAvailable,
            barberId: candidateBarber // Keep track of who is free
        });

        currentTime = addMinutes(currentTime, SLOT_INTERVAL);
    }

    return slots;
};
